import React from 'react'
import Link from 'next/link'
import { getPayloadHMR } from '@payloadcms/next/utilities'
import configPromise from '@payload-config'
import './layout.scss'

export default async function TenantLayout({
  children,
  params,
}: {
  children: React.ReactNode
  params: { tenant: string }
}) {
  const payload = await getPayloadHMR({ config: configPromise })

  const tenantsQuery = await payload.find({
    collection: 'tenants',
    overrideAccess: true,
    where: { slug: { equals: params.tenant } },
    limit: 1,
  })

  const tenant = tenantsQuery.docs?.[0]
  const tenantName = tenant?.name ?? params.tenant
  const slug = params.tenant

  return (
    <div className="site">
      {/* Top bar */}
      <div className="site__topbar">
        <span>Hỗ trợ khách hàng 24/7</span>
        <span>Hotline: 1900 xxxx</span>
      </div>

      {/* Header */}
      <header className="site__header">
        <div className="site__header-inner">
          <Link href={`/${slug}`} className="site__logo">
            <span className="site__logo-main">{tenantName}</span>
          </Link>

          <nav className="site__nav">
            <Link href={`/${slug}`}>Trang chủ</Link>
            <Link href={`/${slug}/tickets`}>Mua vé</Link>
            <Link href={`/${slug}/login`} className="site__nav-login">
              Đăng nhập
            </Link>
          </nav>
        </div>
      </header>

      {/* Page content */}
      <main className="site__main">{children}</main>

      {/* Footer */}
      <footer className="site__footer">
        <div className="site__footer-inner">
          <div className="site__footer-brand">
            <strong>{tenantName}</strong>
            <p>Dịch vụ đặt vé trực tuyến nhanh chóng, tiện lợi.</p>
          </div>
          <div className="site__footer-links">
            <h4>Liên kết</h4>
            <Link href={`/${slug}`}>Trang chủ</Link>
            <Link href={`/${slug}/tickets`}>Danh sách vé</Link>
          </div>
          <div className="site__footer-contact">
            <h4>Liên hệ</h4>
            <p>Email: support@{slug}.vn</p>
            <p>Hotline: 1900 xxxx</p>
          </div>
        </div>
        <div className="site__footer-bottom">
          © {new Date().getFullYear()} {tenantName}. All rights reserved.
        </div>
      </footer>
    </div>
  )
}
